function build_chunks( sub_text, sub_ranges, range_data, container, options ) {
	let text_start = null,
		text_stop = null,
		i,
		remove_r_id,
		r_id,
		sr_id,
		range_id,
		range_info,
		new_i,
		new_sub_text,
		new_sub_range;

	for ( i = 0; i < sub_ranges.length; i++ ) {
		if ( sub_ranges[ i ].index.length == 0 ) {
			if ( text_start == null ) {
				text_start = i;
			}
		} else {
			if ( text_start != null ) {
				text_stop = i;
				container.appendChild(
					document.createTextNode( sub_text.substring( text_start, text_stop ) )
				);
				text_start = null;
				text_stop = null;
			}

			remove_r_id = null;
			for ( r_id in sub_ranges[ i ].index ) {
				if (
					null === remove_r_id ||
					sub_ranges[ i ].index[ r_id ].len > sub_ranges[ i ].index[ remove_r_id ].len
				) {
					remove_r_id = r_id;
				}
			}

			range_id = sub_ranges[ i ].index[ remove_r_id ].id;
			range_info = range_data[ range_id ];
			new_i = i + sub_ranges[ i ].index[ remove_r_id ].len - 1;
			new_sub_text = sub_text.substring( i, i + sub_ranges[ i ].index[ remove_r_id ].len );
			new_sub_range = sub_ranges.slice( i, 1 + i + sub_ranges[ i ].index[ remove_r_id ].len );

			for ( sr_id = 0; sr_id < new_sub_range.length; sr_id++ ) {
				new_sub_range[ sr_id ].index.splice( remove_r_id, 1 );
			}

			container.appendChild(
				render_range( new_sub_text, new_sub_range, range_info, range_data, options )
			);
			i = new_i;
		}
	}
	if ( text_start != null ) {
		container.appendChild(
			document.createTextNode( sub_text.substring( text_start, sub_text.length ) )
		);
	}
	container.normalize();
}

function find_largest_range( rs ) {
	let r_id = -1,
		r_size = 0,
		i;

	if ( rs.length < 1 ) {
		return null;
	}

	for ( i = 0; i < rs.length; i++ ) {
		if ( null === rs[ i ] ) {
			continue;
		}

		if ( -1 === r_id || rs[ i ].indices[ 1 ] - rs[ i ].indices[ 0 ] > r_size ) {
			r_id = i;
			r_size = rs[ i ].indices[ 1 ] - rs[ i ].indices[ 0 ];
		}
	}

	return r_id;
}

