          if (!await exists(depsIncludePath)) {
            await unlink(path.join(depsPath, 'c_api.h'));
            await unlink(path.join(depsPath, 'LICENSE'));

            resources.downloadAndUnpackResource(
                TF_WIN_HEADERS_URI, depsPath, () => {
