                    if (stat.isDirectory()) {
                      scanDir(rootDir, absFile, resource, doNotCopy, callback);
                    } else {
                      var relFile = absFile.substring(rootDir.length + 1).replace(/\\/g, "/");
                      var fileInfo = resources[relFile];
                      delete unconfirmed[relFile];
