function rotateClockwise(buffer) {
  var w = buffer.height;
  var h = buffer.width;
  var w2 = Math.floor(w / 2);
  var h2 = Math.floor(h / 2);
  return makeBuffer(w, h, function(context) {
    context.translate(w2, h2);
    context.rotate(Math.PI / 2);
    context.drawImage(buffer, -h2, -w2);
