function pageRange(selected, numPages, num) {
  let selectedPos = Math.ceil(num / 2);
  let start = (selected < selectedPos) ? 1
    : selected - selectedPos + 1;
  let len = (numPages < start + num - 1) ? numPages - start + 1
    : num;

  return Array
